		{X: rect.Max.X - radius - 1, Y: rect.Min.Y + radius},
		{X: rect.Min.X + radius, Y: rect.Max.Y - radius - 1},
		{X: rect.Max.X - radius - 1, Y: rect.Max.Y - radius - 1},
	}
	rsq := float64(radius * radius)
	for _, corner := range corners {
