 26	type textStats struct {
 27		CharacterCount    int
 28		LineCount         int
 29		UnsupportedCount  int
 30		UnsupportedUnique []rune
 31		DisplayText       string
 32	}
 33	
 34	func sortedLanguages(languages []string) []string {
 35		unique := make([]string, 0, len(languages))
 36		seen := map[string]bool{}
 37		for _, lang := range languages {
 38			if !seen[lang] {
 39				seen[lang] = true
 40				unique = append(unique, lang)
 41			}
 42		}
 43		slices.Sort(unique)
 44		return unique
 45	}
 46	
 47	func supportedRunes(languages []string) map[rune]bool {
 48		supported := map[rune]bool{}
 49		for _, r := range punctuationRunes {
 50			supported[r] = true
 51		}
 52		for _, lang := range languages {
 53			for _, r := range languageRuneSets[lang] {
 54				supported[r] = true
 55			}
 56		}
 57		return supported
 58	}
 59	
 60	func analyzeText(text string, languages []string, uppercaseOnly, autoReplace bool) textStats {
 61		normalized := strings.ReplaceAll(text, "\r\n", "\n")
 62		if uppercaseOnly {
 63			normalized = strings.ToUpper(normalized)
 64		}
 65	
 66		if normalized == "" {
 67			return textStats{
 68				LineCount:   1,
 69				DisplayText: "",
 70			}
 71		}
 72	
 73		supported := supportedRunes(languages)
 74		unsupportedSeen := map[rune]bool{}
 75		unsupportedUnique := make([]rune, 0, 8)
 76		out := strings.Builder{}
 77		charCount := 0
 78	
 79		for _, r := range normalized {
 80			charCount++
 81			if supported[r] {
 82				out.WriteRune(r)
 83				continue
 84			}
 85	
 86			if !unsupportedSeen[r] {
 87				unsupportedSeen[r] = true
 88				unsupportedUnique = append(unsupportedUnique, r)
 89			}
 90	
 91			if autoReplace {
 92				out.WriteRune('?')
 93			} else {
 94				out.WriteRune(r)
 95			}
 96		}
 97	
 98		lineCount := strings.Count(normalized, "\n") + 1
 99		return textStats{
100			CharacterCount:    charCount,
101			LineCount:         lineCount,
102			UnsupportedCount:  len(unsupportedUnique),
103			UnsupportedUnique: unsupportedUnique,
104			DisplayText:       out.String(),
105		}
106	}
